export class Shelf{constructor(e){this.keys=e}url=e=>`https://shelf.toolbomber.com/api/${e}`;append=async e=>this.keys.append&&this.trigger("append",e);replace=async e=>this.keys.replace&&this.trigger("replace",e);clear=async()=>this.keys.replace&&this.trigger("replace",[]);read=async()=>this.get();get=async()=>await fetch(`${this.url("read")}/?key=${this.keys.read}`).then((e=>e.json())).catch((e=>console.log(e)));static create=async e=>new Shelf((await Shelf.generateKeys(e)).keys);static generateKeys=async e=>fetch((new Shelf).url("create"),{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({seed:e})}).then((e=>e.json())).catch((e=>{console.error("Error:",e)}));trigger=async(e,t)=>fetch(this.url(e),{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({key:this.keys[e],data:t})}).then((e=>e.json())).catch((e=>{console.error("Error:",e)}))}